head.script:
scwin.selpchClsCd = "1"; //매출입구분코드
scwin.MSG_FS_WRN_013 = "청구 데이타가 존재하지 않습니다.";				
scwin.MSG_FS_WRN_014 = "청구취소 데이타가 존재하지 않습니다.";				
scwin.MSG_FS_WRN_015 = "청구는 내부거래상태가 등록일때만 가능합니다.";						
scwin.MSG_FS_WRN_016 = "청구취소는 내부거래상태가 청구일때만 가능합니다.";	

scwin.vLoginCoCd = $c.data.getMemInfo("coCd");
scwin.vCoCd = $c.gus.cfIsNull(scwin.vLoginCoCd)?'':scwin.vLoginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)	
scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 

scwin.isSubCompany = false;
scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = scwin.strCurDate.substring(0,6) + "01";


// 파라미터 정의
scwin.params = $c.data.getParameter(); // 호출시 파라미터 전체(Json으로 반아옴)
//회사조회 1번체크 후 확인하기 위해 기본값 설정함.
scwin.flag = "";
scwin.selPchLodeptCd = "";
scwin.qryConDt = "";
scwin.qryConLastDt = "";
//-------------------------------------------------------------------------
// hidden
//-------------------------------------------------------------------------
scwin.txtCoClsCd ="";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    try{
        // 파라미터 세팅
        scwin.flag = scwin.params.flag == null ? "" : scwin.params.flag;
        scwin.bizDom = scwin.params.bizDom == null ? "" : scwin.params.bizDom;
        scwin.selPchLodeptCd = scwin.params.selPchLodeptCd == null ? "" : scwin.params.flagselPchLodeptCd;
        scwin.qryConDt = scwin.params.qryConDt == null ? "" : scwin.params.qryConDt;
        scwin.qryConLastDt = scwin.params.qryConLastDt == null ? "" : scwin.params.qryConLastDt;
        scwin.acctNm = scwin.params.acctNm == null ? "" : scwin.params.acctNm;
        scwin.strbilgClntNo = scwin.params.strbilgClntNo == null ? "" : scwin.params.strbilgClntNo;
        scwin.strbilgClntNm = scwin.params.strbilgClntNm == null ? "" : scwin.params.strbilgClntNm;
        scwin.strlobranCd = scwin.params.strlobranCd == null ? "" : scwin.params.strlobranCd;
        scwin.strlobranNm = scwin.params.strlobranNm == null ? "" : scwin.params.strlobranNm;

        scwin.privAdmin = $c.data.getMemInfo("privAdmin");
        scwin.crn = scwin.params.crn;

        //parent.tabFrame.f_FoldMenu(true); //TOBE 미사용
    } catch (e) {
       console.log("onpageload : " +e);
    }
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 

};  

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log("f_setCompanyInfo : " +e);
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {

    /*
    var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
                                ,ed_coCd.text, txt_coNm.value
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null);
    */
    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의  Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의  Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};

//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");	// 코드
            ed_coNm.setValue("");	// 회사명
            scwin.txtCoClsCd ="";	// 회사구분    
        }

        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if ( scwin.isStarted == true ) {
            if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
            }

            acb_gubun1.setSelectedIndex(0);
            div_qryConKnd1.show();
            div_qryConKnd2.hide();
            ed_rsltsDtSt.setValue(scwin.strPreDate);
            ed_rsltsDtEnd.setValue(scwin.strCurDate);
            ed_bilgClntNo.setValue(scwin.strbilgClntNo);
            ed_txt_bilgClntNm.setValue(scwin.strbilgClntNm);
            ed_bilgLodeptCd.setValue(scwin.strlobranCd);
            ed_txt_bilgLodeptNm.setValue(scwin.strlobranNm);

            //계정별 확정/미확정 조회 링크시
		    if(scwin.flag != ""){
                //TOBE 자회사는 호출하는 페이지는 없는것으로 확인. fs_103_04_01 소스를 참조함
                scwin.ds_parent = scwin.params.dma_queryConditionDTO; //var ds_parent = eval("parent."+flag).ds_selldecunsetaggr_con;						

                ds_selldecunsetaggr_con.setArray({"columnInfo" : dataColumn 
                                , "data" : scwin.ds_parent});
                scwin.f_WholeRetrieve();
            }

            if(scwin.selPchLodeptCd != ""){
                //TOBE 자회사는 호출하는 페이지는 없는것으로 확인
                scwin.f_executeFromLinked();
            }
        }
    } catch (e) {
       console.log("udc_coCd_callBackFunc" + e);
    }
};

//-------------------------------------------------------------------------------
//scwin.selPchLodeptCd 값이 존재시 조회 (다른페이지에서 링크로 걸때)
//-------------------------------------------------------------------------------
scwin.f_executeFromLinked = function () {
    try{
        ed_bilgLodeptCd.setValue(scwin.selPchLodeptCd);
        ed_rsltsDtSt.setValue(scwin.qryConDt + "01");
        ed_rsltsDtEnd.setValue(scwin.qryConLastDt);
        scwin.f_RetrieveCustomerEachUnityPurchase();
    } catch (e) {
       console.log("f_executeFromLinked" + e);
    }
};

//-------------------------------------------------------------------------------
//계정별 확정/미확정 호출시 조회
//-------------------------------------------------------------------------------
scwin.f_WholeRetrieve = function () {
    try{
        ed_bilgLodeptCd.setValue(ds_selldecunsetaggr_con.get("bilgLodeptCd"));
        scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), ed_txt_bilgLodeptNm.getValue(), 'T', 'T');
        ed_rsltsDtSt.setValue(ds_selldecunsetaggr_con.get("qryConDtFm"));
        ed_rsltsDtEnd.setValue(ds_selldecunsetaggr_con.get("qryConDtTo"));
        scwin.f_RetrieveCustomerEachUnityPurchase();
    } catch (e) {
       console.log("f_WholeRetrieve" + e);
    }
};

//-------------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------------
scwin.f_RetrieveCustomerEachUnityPurchase = async function () {
    try{
        let ret = await $c.gus.cfValidate([ed_bilgLodeptCd,ed_rsltsDtSt,ed_rsltsDtEnd]);
        if (!ret){
            return false;
        }
        //조회시작일자가 더 클경우 체크
        if (acb_gubun1.getValue() == "RSLTS_DT" || acb_gubun1.getValue() == "ODR_DT" || acb_gubun1.getValue() == "INTEND_DT" || acb_gubun1.getValue() == "POST_DT") {
            let ret2 = await $c.gus.cfValidate([ed_rsltsDtSt, ed_rsltsDtEnd]);
            if (!ret2){
                return false;
            }

            if (!$c.gus.cfIsAfterDate(ed_rsltsDtSt.getValue(),ed_rsltsDtEnd.getValue())) {
                await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
                ed_rsltsDtSt.focus();
                return false;;
            }
        }

        const params = {
            coCd        : ed_coCd.getValue() ,
            gubun1      : acb_gubun1.getValue() ,
            bilgLodeptCd: ed_bilgLodeptCd.getValue() ,
            pchsDeptCd  : ed_bilgLodeptCd.getValue() ,
            odrNo       : ed_odrNo.getValue() ,
            bilgClntNo  : ed_bilgClntNo.getValue() ,
            pchsClntNo  : ed_bilgClntNo.getValue() ,
            rsltsDtSt   : ed_rsltsDtSt.getValue() ,
            rsltsDtEnd  : ed_rsltsDtEnd.getValue() ,
            regId       : ed_regId.getValue() ,
            modId       : ed_modId.getValue() ,
            aggbilgClntNo : ed_bilgClntNo.getValue() ,
        };

        //데이터셋에 정보설정
        ds_selldecunsetaggr_con.setJSON(params);
        ds_customerEachUnityPurchaseList.removeAll();
        $c.sbm.execute(sbm_queryConditionDTO);
    } catch (e) {
       console.log("f_RetrieveCustomerEachUnityPurchase" + e);
    }
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_queryConditionDTO_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        // 총 조회건수 표시

        $c.gus.cfGoPrevPosition(gr_customerEachUnityPurchaseList, 0);

        if (ds_customerEachUnityPurchaseList.getRowCount() == 0) {
		    ds_customerEachUnityPurchaseList.removeAll();
        }else{
            tbx_totalRows.setValue($c.gus.cfInsertComma(ds_customerEachUnityPurchaseList.getRowCount()));
            scwin.f_RetrieveOrderEachUnityPurchase("0");//f_RetrieveOrderEachUnityPurchase("1");
        }

    } catch (e) {
       console.log("sbm_queryConditionDTO_submitdone" + e);
    }
};       

//-------------------------------------------------------------------------------
// 오더별 매입 현황 조회
//-------------------------------------------------------------------------------
scwin.f_RetrieveOrderEachUnityPurchase = function (row) {
    try{
        ds_selldecunsetaggr_con.set("pchsClntNoDtl", ds_customerEachUnityPurchaseList.getCellData(row, "pchsClntNo"));

        // 오더별 매입현황 전체
   		if (chb_totalYn.getValue() == "1") {
            ds_selldecunsetaggr_con.set("totalYn","B");
        }else{
            ds_selldecunsetaggr_con.set("totalYn","A");
        }

        ds_orderEachUnityPurchaseList.removeAll();
        $c.sbm.execute(sbm_queryConditionDTODtl);

    } catch (e) {
       console.log("f_RetrieveOrderEachUnityPurchase" + e);
    }
};  


//-------------------------------------------------------------------------
// 오더별 매입 현황 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_queryConditionDTODtl_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        // 총 조회건수 표시
        tbx_totalRows2.setValue($c.gus.cfInsertComma(ds_orderEachUnityPurchaseList.getRowCount()));

        if (ds_orderEachUnityPurchaseList.getRowCount() == 0) {
		    //cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        }else{
            $c.gus.cfGoPrevPosition(gr_orderEachUnityPurchaseList, 0);

            //ASIS edit 처리
            //id=chk  edit={decode(dcsnClsNm, "미확인","true","false")}
            //<c> id=pchsClntNm  	name=거래처명  edit={decode(dcsnClsNm, "미확인","true","false")}
            //<c> id=vat  			name=부가세  edit={decode(dcsnClsNm, "미확인","true","false")}
            for (let i=0; i < ds_orderEachUnityPurchaseList.getRowCount(); i++){
                if (ds_orderEachUnityPurchaseList.getCellData(i,"dcsnClsNm") =="미확인"){
                    gr_orderEachUnityPurchaseList.setReadOnly("cell",i,"chk",false); 
                    gr_orderEachUnityPurchaseList.setReadOnly("cell",i,"pchsClntNm",false); 
                    gr_orderEachUnityPurchaseList.setReadOnly("cell",i,"vat",false);
                }
            }
        }
    } catch (e) {
       console.log("sbm_queryConditionDTODtl_submitdone" + e);
    }
};     

//-------------------------------------------------------------------------
// 저장 (ASIS 주석이나 소스만 살림)
//-------------------------------------------------------------------------
scwin.f_save = async function(e) {
    try{
        if(await $c.win.confirm(MSG_CM_CRM_001)) { //저장하시겠습니까?
            if(ds_orderEachUnityPurchaseList.getModifiedIndex().length > 0){
                let checkedCnt = 0;

                for (let i=0; i < ds_orderEachUnityPurchaseList.getRowCount(); i++){
                    if (ds_orderEachUnityPurchaseList.getCellData(i, "chk") == "T") {
                        checkedCnt++;
                        break;
                    }
                }

                if (checkedCnt == 0) {
                    $c.win.alert("체크된 데이터가 없습니다.");
                    return false;
                }

                let ret = await $c.gus.cfValidate([gr_orderEachUnityPurchaseList]);
                if (!ret){
                    return false;
                }

            } else {
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,["통합매입일괄수정"]));//@은(는) 변경된 사항이 없습니다.
            }
        }
    } catch (e) {
       console.log("f_save" + e);
    }
};     

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function (e) {
    $c.gus.cfInitObjects(tbl_search, [ed_bilgLodeptCd,ed_txt_bilgLodeptNm,ed_rsltsDtSt,ed_rsltsDtEnd]);
};

//-------------------------------------------------------------------------
// 엑셀 다운로드
//-------------------------------------------------------------------------
scwin.f_downExcelSheet1 = async function() {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            const options = {
            fileName : "통합매출상세.xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            , sheetName : "통합매출상세"
            , bodyWordwrap   : true    // 줄바꿈
        };
        const infoArr = [];
        $c.data.downloadGridViewExcel(gr_customerEachUnityPurchaseList, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// 엑셀 다운로드(오더별 매입 현황)
//-------------------------------------------------------------------------
scwin.f_downExcelSheet2 = async function() {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            const options = {
            fileName : "통합매출상세.xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            , sheetName : "통합매출상세"
            , bodyWordwrap   : true    // 줄바꿈
        };
        const infoArr = [];
        $c.data.downloadGridViewExcel(gr_orderEachUnityPurchaseList, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail =  function(arg) {
    try{
        let strPath = "";
        let paramObj = {};
        let menuNm = "";
        let menuId = "";
        strPath = "/ui/ja/ds/fs/adjm/ja_fs_101_01_03b.xml"; //ja_fs_101_01_03b 화면 미개발인듯 2026.03.30
        menuNm = "기타원가생성";
        menuId = "ja_fs_101_01_03b";
        paramObj = {
            odrNo: arg ,
            flag: "DETAIL" ,
        }
        $c.win.openMenu(menuNm, strPath, menuId, paramObj, { openAction: "exist" });
    } catch (e) {
       console.log("f_orderDetail" + e);
    }
};     

//-------------------------------------------------------------------------
// 삭제이력 버튼 클릭시 팝업 화면 호출
//-------------------------------------------------------------------------
scwin.f_retrieveDeleteHistory =  function(arg) {
    try{

        let data = {
            bilgLodeptCd    : ed_bilgLodeptCd.getValue() , 
            qryConDtFm      : ed_rsltsDtSt.getValue() , 
            qryConDtTo      : ed_rsltsDtEnd.getValue() , 
            gubun           : "매입" ,
            //coCd            : ed_coCd.getValue() ,  //(as-is 소스오류) 온로드 시 f_setCompanyInfo 다음 로직이 진행되지 않음
            coCd            : "" ,  //(as-is 소스오류) 온로드 시 f_setCompanyInfo 다음 로직이 진행되지 않음
            bilgLodeptNm    : ed_txt_bilgLodeptNm.getValue() , 
        };

        let opts = {
            id : "ja_fs_204_02_04p",	
            popupName : "삭제이력조회",
            modal : true,
            type : "browserPopup" ,
            title : "",
            width : "1100",
            height : "750",
            scrollbars : "no",
        }
        $c.win.openPopup("/ui/ja/ds/fs/bilg/ja_fs_204_02_04p.xml", opts, data);

    } catch (e) {
       console.log("f_retrieveDeleteHistory" + e);
    }
};

//-------------------------------------------------------------------------
// 매입부서코드
// f_IsPopUp 내부처리로 수정
//-------------------------------------------------------------------------
scwin.udc_bilgLodept_onblurCodeEvent = function (e) {
    if (ed_bilgLodeptCd.getValue() != ed_bilgLodeptCd.hidVal){
            ed_txt_bilgLodeptNm.setValue("");
    }
    if (ed_bilgLodeptCd.getValue().trim() != "" ) {
