                        , null                            // 중복체크여부	("F")
                        , pAllSearch                      // 전체검색허용여부	("F")
                        , "등록자,사용자ID,사용자명"       // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
                break;

            default:
                break;
        }	

    } catch (e) {
       console.log("f_openCommonPopUp :" + e);
    }
};

