//-------------------------------------------------------------------------
scwin.gr_orderEachUnityPurchaseList_onafteredit = function (rowIndex, columnIndex, value) {
    try{
        let colid = gr_orderEachUnityPurchaseList.getColumnID(columnIndex);

        switch (colid) {
            case "pchsClntNm": //청구처
                if ( ds_orderEachUnityPurchaseList.getCellData(rowIndex, "dcsnClsCd") != "1"  ){
                    return false;
                }
            let olddata = ds_orderEachUnityPurchaseList.getOriginalCellData(rowIndex, colid);    
            scwin.f_openPopUpGridBefore("NM", ds_orderEachUnityPurchaseList, "pchsClntNo", colid, olddata, 1, "T");
            break;
        }

    } catch (e) {
       console.log("gr_orderEachUnityPurchaseList_onafteredit :" + e);
    } 
};

//-------------------------------------------------------------------------
// 그리드에서 팝업오픈하기전 작업(코드와 코드명이 있는 경우)
//-------------------------------------------------------------------------
scwin.f_openPopUpGridBefore = function (colGubun, ds, cdColid, nmColid, olddata, gubun, pWinCloseTF) {
    try{
        let cdVal = ds_orderEachUnityPurchaseList.getCellData(ds_orderEachUnityPurchaseList.getRowPosition(), cdColid);
        let nmVal = ds_orderEachUnityPurchaseList.getCellData(ds_orderEachUnityPurchaseList.getRowPosition(), nmColid);

        //ds사용 오류로 데이터셋 명칭 ds_orderEachUnityPurchaseList로 대체함.

        if(colGubun == "CD"){
            if(cdVal == ""){
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), nmColid, "");
            }else{
                if(nmVal != olddata){	
                    ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), nmColid, "");
                    scwin.f_openPopUpGrid(ds_orderEachUnityPurchaseList, cdColid, nmColid, gubun, pWinCloseTF);
                }
            }

        }else if(colGubun == "NM"){
            if(nmVal == ""){
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), cdColid, "");
            }else{
                if(nmVal != olddata){	
                    ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), cdColid, "");
                    scwin.f_openPopUpGrid(ds_orderEachUnityPurchaseList, cdColid, nmColid, gubun, pWinCloseTF);
                }
            }
        }
    } catch (e) {
       console.log("f_openPopUpGridBefore :" + e);
    } 
};

