//-------------------------------------------------------------------------
// 그리드 매입거래처 콜백 (pchsClntNm)
//-------------------------------------------------------------------------
scwin.grd_pchsClntNo_callbackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;
        //pchsClntNo, pchsClntNm (cdColid, nmColid);

        if (rtnList != null ) {
            if(rtnList[0] == "N/A"){ //팝업에서 닫기버튼 클릭시
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNo" , ds_orderEachUnityPurchaseList.getOriginalCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNo"));
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNm" , ds_orderEachUnityPurchaseList.getOriginalCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNm"));
            }else{
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNo" , rtnList[0]);
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNm" , rtnList[1]);
                ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "chk" ,"T");
	        }
        }else{
            ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNo" , "");
	        ds_orderEachUnityPurchaseList.setCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNm" , "");
        }

    } catch (e) {
       console.log("grd_pchsClntNo_callbackFunc :" + e);
    } 
};

//-------------------------------------------------------------------------
// 오더별 매입 현황 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.gr_orderEachUnityPurchaseList_ontextimageclick = function (rowIndex, columnIndex) {
    try{
        let colid = gr_orderEachUnityPurchaseList.getColumnID(columnIndex);

        //찾기버튼의 경우 gr_orderEachUnityPurchaseList_onafteredit와 같이 뜬다. 어쩔까나...실제 저장이 없어서 화면은 의미는 없다.
        switch (colid) {
            case "pchsClntNm": //청구처
                if ( ds_orderEachUnityPurchaseList.getCellData(rowIndex, "dcsnClsCd") != "1"  ){
                    alert("확정구분이 미확인 상태만 수정할 수 있습니다.");
                    return false;
                }

            scwin.f_openPopUpGrid(ds_orderEachUnityPurchaseList, "pchsClntNo", colid, 1, "F");
            break;
        }

    } catch (e) {
       console.log("gr_orderEachUnityPurchaseList_onafteredit :" + e);
    } 
};


